  wire _c02 = ((x[0] * W0)[1] & (x[1] * W1)[1]) | ((x[0] * W0)[1] & _c01) | ((x[1] * W1)[1] & _c01);
  wire _n03 = (x[0] * W0)[2] ^ (x[1] * W1)[2] ^ _c02;
