  wire _n04 = (x[0] * W0)[3] ^ (x[1] * W1)[3] ^ _c03;
  wire _c04 = ((x[0] * W0)[3] & (x[1] * W1)[3]) | ((x[0] * W0)[3] & _c03) | ((x[1] * W1)[3] & _c03);
  assign weighted_sum = {_n01, _n02, _n03, _n04};
    assign y = (weighted_sum > THRESHOLD) ? 1'b1 : 1'b0;

