      wire _n01 = x0 + x1 + x2 + x3[0] ^ x4[0];
  wire _c01 = x0 + x1 + x2 + x3[0] & x4[0];
  wire _n02 = x0 + x1 + x2 + x3[1] ^ x4[1] ^ _c01;
  wire _c02 = (x0 + x1 + x2 + x3[1] & x4[1]) | (x0 + x1 + x2 + x3[1] & _c01) | (x4[1] & _c01);
  wire _n03 = x0 + x1 + x2 + x3[2] ^ x4[2] ^ _c02;
  wire _c03 = (x0 + x1 + x2 + x3[2] & x4[2]) | (x0 + x1 + x2 + x3[2] & _c02) | (x4[2] & _c02);
  wire _n04 = x0 + x1 + x2 + x3[3] ^ x4[3] ^ _c03;
  wire _c04 = (x0 + x1 + x2 + x3[3] & x4[3]) | (x0 + x1 + x2 + x3[3] & _c03) | (x4[3] & _c03);
  assign sum_x = {_n01, _n02, _n03, _n04};
    assign sum_y = y0 + y1 + y2 + y3 + y4;
