module ripple_carry_adder (
    input [3:0] A,
    input [3:0] B,
    input Cin,
    output [3:0] Sum,
    output Cout
);
    wire [3:0] carry;

    // Full Adder for bit 0
      wire _n01 = A[0] + B[0][0] ^ Cin[0];
  wire _c01 = A[0] + B[0][0] & Cin[0];
  wire _n02 = A[0] + B[0][1] ^ Cin[1] ^ _c01;
  wire _c02 = (A[0] + B[0][1] & Cin[1]) | (A[0] + B[0][1] & _c01) | (Cin[1] & _c01);
  wire _n03 = A[0] + B[0][2] ^ Cin[2] ^ _c02;
  wire _c03 = (A[0] + B[0][2] & Cin[2]) | (A[0] + B[0][2] & _c02) | (Cin[2] & _c02);
  wire _n04 = A[0] + B[0][3] ^ Cin[3] ^ _c03;
  wire _c04 = (A[0] + B[0][3] & Cin[3]) | (A[0] + B[0][3] & _c03) | (Cin[3] & _c03);
  assign {carry[0], Sum[0]} = {_n01, _n02, _n03, _n04};
    // Full Adder for bit 1
    assign {carry[1], Sum[1]} = A[1] + B[1] + carry[0];
    // Full Adder for bit 2
    assign {carry[2], Sum[2]} = A[2] + B[2] + carry[1];
    // Full Adder for bit 3
    assign {Cout, Sum[3]} = A[3] + B[3] + carry[2];
endmodule

module carry_save_adder (
    input [3:0] a,
    input [3:0] b,
    input [3:0] c,
    output [3:0] sum,
    output carry_out
);
    wire [4:0] tmp_sum1, tmp_sum2;

    // First stage of addition: add a and b
      wire _n01 = a[0] ^ b[0];
  wire _c01 = a[0] & b[0];
  wire _n02 = a[1] ^ b[1] ^ _c01;
  wire _c02 = (a[1] & b[1]) | (a[1] & _c01) | (b[1] & _c01);
  wire _n03 = a[2] ^ b[2] ^ _c02;
  wire _c03 = (a[2] & b[2]) | (a[2] & _c02) | (b[2] & _c02);
  wire _n04 = a[3] ^ b[3] ^ _c03;
  wire _c04 = (a[3] & b[3]) | (a[3] & _c03) | (b[3] & _c03);
  assign tmp_sum1 = {_n01, _n02, _n03, _n04};

    // Second stage of addition: add the result with c
    assign tmp_sum2 = tmp_sum1 + c;

    // Final sum and carry out
    assign sum = tmp_sum2[3:0];
    assign carry_out = tmp_sum2[4];

endmodule

module carry_save_adder(
    input [3:0] a,
    input [3:0] b,
    input [3:0] c,
    output [4:0] sum
);
