  wire _c02 = ((feature1 * weight1) + (feature2 * weight2) + (feature3 * weight3)[1] & bias[1]) | ((feature1 * weight1) + (feature2 * weight2) + (feature3 * weight3)[1] & _c01) | (bias[1] & _c01);
