  wire _c03 = ((feature1 * weight1) + (feature2 * weight2) + (feature3 * weight3)[2] & bias[2]) | ((feature1 * weight1) + (feature2 * weight2) + (feature3 * weight3)[2] & _c02) | (bias[2] & _c02);
