                (pixel20 * -1) + (pixel21 * 0)[3] ^ (pixel22 * 1)[3] ^ _c03;
  wire _c04 = ((pixel00 * -1) + (pixel01 * 0) + (pixel02 * 1) +
                (pixel10 * -2) + (pixel11 * 0) + (pixel12 * 2) +
                (pixel20 * -1) + (pixel21 * 0)[3] & (pixel22 * 1)[3]) | ((pixel00 * -1) + (pixel01 * 0) + (pixel02 * 1) +
                (pixel10 * -2) + (pixel11 * 0) + (pixel12 * 2) +
                (pixel20 * -1) + (pixel21 * 0)[3] & _c03) | ((pixel22 * 1)[3] & _c03);
  assign Gx = {_n01, _n02, _n03, _n04};

    assign Gy = (pixel00 * -1) + (pixel01 * -2) + (pixel02 * -1) +
                (pixel10 * 0) + (pixel11 * 0) + (pixel12 * 0) +
                (pixel20 * 1) + (pixel21 * 2) + (pixel22 * 1);

    assign gradient_magnitude = (Gx < 0 ? -Gx : Gx) + (Gy < 0 ? -Gy : Gy);
endmodule

