  wire _n02 = (h0 * x0) + (h1 * x1)[1] ^ (h2 * x2)[1] ^ _c01;
  wire _c02 = ((h0 * x0) + (h1 * x1)[1] & (h2 * x2)[1]) | ((h0 * x0) + (h1 * x1)[1] & _c01) | ((h2 * x2)[1] & _c01);
  wire _n03 = (h0 * x0) + (h1 * x1)[2] ^ (h2 * x2)[2] ^ _c02;
