  wire _n04 = (a * x1) + (b * x2)[3] ^ c[3] ^ _c03;
  wire _c04 = ((a * x1) + (b * x2)[3] & c[3]) | ((a * x1) + (b * x2)[3] & _c03) | (c[3] & _c03);
