      wire _n01 = 8 * binary[3] + 4 * binary[2] + 2 * binary[1][0] ^ binary[0][0];
  wire _c01 = 8 * binary[3] + 4 * binary[2] + 2 * binary[1][0] & binary[0][0];
  wire _n02 = 8 * binary[3] + 4 * binary[2] + 2 * binary[1][1] ^ binary[0][1] ^ _c01;
  wire _c02 = (8 * binary[3] + 4 * binary[2] + 2 * binary[1][1] & binary[0][1]) | (8 * binary[3] + 4 * binary[2] + 2 * binary[1][1] & _c01) | (binary[0][1] & _c01);
  wire _n03 = 8 * binary[3] + 4 * binary[2] + 2 * binary[1][2] ^ binary[0][2] ^ _c02;
  wire _c03 = (8 * binary[3] + 4 * binary[2] + 2 * binary[1][2] & binary[0][2]) | (8 * binary[3] + 4 * binary[2] + 2 * binary[1][2] & _c02) | (binary[0][2] & _c02);
  wire _n04 = 8 * binary[3] + 4 * binary[2] + 2 * binary[1][3] ^ binary[0][3] ^ _c03;
  wire _c04 = (8 * binary[3] + 4 * binary[2] + 2 * binary[1][3] & binary[0][3]) | (8 * binary[3] + 4 * binary[2] + 2 * binary[1][3] & _c03) | (binary[0][3] & _c03);
  assign decimal = {_n01, _n02, _n03, _n04};

endmodule

