module full_adder_4bit(
    input [3:0] a,      // 4-bit binary input.
    input [3:0] b,      // 4-bit binary input.
    input cin,          // Carry-in bit.
    output [3:0] sum,   // 4-bit sum output.
    output cout         // Carry-out bit.
);

wire c1, c2, c3;

// Full adder logic
  wire _n01 = a[0] + b[0][0] ^ cin[0];
  wire _c01 = a[0] + b[0][0] & cin[0];
  wire _n02 = a[0] + b[0][1] ^ cin[1] ^ _c01;
  wire _c02 = (a[0] + b[0][1] & cin[1]) | (a[0] + b[0][1] & _c01) | (cin[1] & _c01);
  wire _n03 = a[0] + b[0][2] ^ cin[2] ^ _c02;
  wire _c03 = (a[0] + b[0][2] & cin[2]) | (a[0] + b[0][2] & _c02) | (cin[2] & _c02);
  wire _n04 = a[0] + b[0][3] ^ cin[3] ^ _c03;
  wire _c04 = (a[0] + b[0][3] & cin[3]) | (a[0] + b[0][3] & _c03) | (cin[3] & _c03);
  assign {c1, sum[0]} = {_n01, _n02, _n03, _n04};
assign {c2, sum[1]} = a[1] + b[1] + c1;
assign {c3, sum[2]} = a[2] + b[2] + c2;
assign {cout, sum[3]} = a[3] + b[3] + c3;

endmodule

module top_module(
    Y   ,
    A1  ,
    A2  ,
    A3  ,
    B1  ,
    VPWR,
    VGND
);output Y   ;
    input  A1  ;
    input  A2  ;
    input  A3  ;
    input  B1  ;
    input  VPWR;
    input  VGND;

    wire A1_high;
    wire A2_high;
    wire A3_high;
    wire B1_high;

      wire _n01 = A1[0] ^ 1'b1[0];
  wire _n02 = A1[1] ^ 1'b1[1];
  wire _n03 = A1[2] ^ 1'b1[2];
  wire _n04 = A1[3] ^ 1'b1[3];
  assign A1_high = ~_n01 & ~_n02 & ~_n03 & ~_n04;
    assign A2_high = (A2 == 1'b1);
    assign A3_high = (A3 == 1'b1);
    assign B1_high = (B1 == 1'b1);

    assign Y = (A1_high | (!A1_high & A2_high) | (!A1_high & !A2_high & A3_high) | (!A1_high & !A2_high & !A3_high & B1_high)) ? 1'b1 : 1'b0;

endmodule

