  wire _n02 = A[0] + B[0][1] ^ Cin[1] ^ _c01;
  wire _c02 = (A[0] + B[0][1] & Cin[1]) | (A[0] + B[0][1] & _c01) | (Cin[1] & _c01);
  wire _n03 = A[0] + B[0][2] ^ Cin[2] ^ _c02;
  wire _c03 = (A[0] + B[0][2] & Cin[2]) | (A[0] + B[0][2] & _c02) | (Cin[2] & _c02);
  wire _n04 = A[0] + B[0][3] ^ Cin[3] ^ _c03;
  wire _c04 = (A[0] + B[0][3] & Cin[3]) | (A[0] + B[0][3] & _c03) | (Cin[3] & _c03);
  assign {carry[0], Sum[0]} = {_n01, _n02, _n03, _n04};
    assign {carry[1], Sum[1]} = A[1] + B[1] + carry[0];
    assign {carry[2], Sum[2]} = A[2] + B[2] + carry[1];
