module ACS
(
   path_0_valid,
   path_1_valid,
   path_0_bmc,
   path_1_bmc,
   path_0_pmc,
   path_1_pmc,
   selection,
   valid_o,
   path_cost
);
   input       path_0_valid;
   input [1:0] path_0_bmc;
   input [7:0] path_0_pmc;
   input       path_1_valid;
   input [1:0] path_1_bmc;
   input [7:0] path_1_pmc;
   output reg        selection;
   output reg        valid_o;
   output      [7:0] path_cost;  
   wire  [7:0] path_cost_0;
   wire  [7:0] path_cost_1;
     wire _n01 = path_0_bmc[0] ^ path_0_pmc[0];
  wire _c01 = path_0_bmc[0] & path_0_pmc[0];
  wire _n02 = path_0_bmc[1] ^ path_0_pmc[1] ^ _c01;
  wire _c02 = (path_0_bmc[1] & path_0_pmc[1]) | (path_0_bmc[1] & _c01) | (path_0_pmc[1] & _c01);
  wire _n03 = path_0_bmc[2] ^ path_0_pmc[2] ^ _c02;
  wire _c03 = (path_0_bmc[2] & path_0_pmc[2]) | (path_0_bmc[2] & _c02) | (path_0_pmc[2] & _c02);
  wire _n04 = path_0_bmc[3] ^ path_0_pmc[3] ^ _c03;
  wire _c04 = (path_0_bmc[3] & path_0_pmc[3]) | (path_0_bmc[3] & _c03) | (path_0_pmc[3] & _c03);
  assign path_cost_0 = {_n01, _n02, _n03, _n04};
   assign path_cost_1  =  path_1_bmc + path_1_pmc;
   assign path_cost      =  (valid_o?(selection?path_cost_1:path_cost_0):7'd0);   
   always @ (*)
   begin
      valid_o = 1'b1;
      case({path_0_valid,path_1_valid})
         2'b00:
         begin
            selection = 1'b0;
            valid_o   = 1'b0; 
         end
         2'b01:   selection = 1'b1;
         2'b10:   selection = 1'b0;
         2'b11:   selection = (path_cost_0 > path_cost_1)?1'b1:1'b0;
       endcase
   end
endmodule

module	tlu_addern_32 (din, incr, sum);
parameter ADDER_DATA_WIDTH = 33;
parameter INCR_DATA_WIDTH  =  1;
parameter UPPER_DATA_WIDTH =  ADDER_DATA_WIDTH - INCR_DATA_WIDTH;
input	[ADDER_DATA_WIDTH-1:0]	din;
input	[INCR_DATA_WIDTH-1:0]   incr;
output	[ADDER_DATA_WIDTH-1:0]	sum;
  wire _n01 = din[ADDER_DATA_WIDTH-1:0][0] ^ {{UPPER_DATA_WIDTH{1'b0}},incr[INCR_DATA_WIDTH-1:0]}[0];
  wire _c01 = din[ADDER_DATA_WIDTH-1:0][0] & {{UPPER_DATA_WIDTH{1'b0}},incr[INCR_DATA_WIDTH-1:0]}[0];
