module usbf_fifo
(
     input           clk_i
    ,input           rst_i
    ,input  [  7:0]  data_i
    ,input           push_i
    ,input           pop_i
    ,input           flush_i
    ,output          full_o
    ,output          empty_o
    ,output [  7:0]  data_o
);
parameter WIDTH   = 8;
parameter DEPTH   = 4;
parameter ADDR_W  = 2;
localparam COUNT_W = ADDR_W + 1;
reg [WIDTH-1:0]         ram [DEPTH-1:0];
reg [ADDR_W-1:0]        rd_ptr;
reg [ADDR_W-1:0]        wr_ptr;
reg [COUNT_W-1:0]       count;
always @ (posedge clk_i or posedge rst_i)
if (rst_i)
begin
    count   <= {(COUNT_W) {1'b0}};
    rd_ptr  <= {(ADDR_W) {1'b0}};
    wr_ptr  <= {(ADDR_W) {1'b0}};
end
else
begin
    if (flush_i)
    begin
        count   <= {(COUNT_W) {1'b0}};
        rd_ptr  <= {(ADDR_W) {1'b0}};
        wr_ptr  <= {(ADDR_W) {1'b0}};
    end
    if (push_i & ~full_o)
    begin
        ram[wr_ptr] <= data_i;
        wr_ptr      <= wr_ptr + 1;
    end
    if (pop_i & ~empty_o)
    begin
        rd_ptr      <= rd_ptr + 1;
    end
    if ((push_i & ~full_o) & ~(pop_i & ~empty_o))
    begin
        count <= count + 1;
    end
    else if (~(push_i & ~full_o) & (pop_i & ~empty_o))
    begin
        count <= count - 1;
    end
end
  wire _n01 = count[0] ^ DEPTH[0];
  wire _n02 = count[1] ^ DEPTH[1];
  wire _n03 = count[2] ^ DEPTH[2];
  wire _n04 = count[3] ^ DEPTH[3];
  assign full_o = ~_n01 & ~_n02 & ~_n03 & ~_n04;
assign empty_o   = (count == 0);
assign data_o    = ram[rd_ptr];
endmodule

module calc(
  input [7:0] A,
  input [7:0] B,
  input OP,
  output [7:0] C
);

  wire [7:0] sum;
  wire [7:0] diff;

    wire _n01 = A[0] ^ B[0];
  wire _c01 = A[0] & B[0];
  wire _n02 = A[1] ^ B[1] ^ _c01;
  wire _c02 = (A[1] & B[1]) | (A[1] & _c01) | (B[1] & _c01);
  wire _n03 = A[2] ^ B[2] ^ _c02;
  wire _c03 = (A[2] & B[2]) | (A[2] & _c02) | (B[2] & _c02);
  wire _n04 = A[3] ^ B[3] ^ _c03;
  wire _c04 = (A[3] & B[3]) | (A[3] & _c03) | (B[3] & _c03);
  assign sum = {_n01, _n02, _n03, _n04};
  assign diff = A - B;

  assign C = OP ? diff : sum;

endmodule

module binary_adder(
    input [3:0] A,
    input [3:0] B,
    output [3:0] S,
    output C_out
);

wire [4:0] temp; // Temporary signal to hold the sum

// Add the two input values, and store the result in the temporary signal
  wire _n01 = {1'b0, A}[0] ^ {1'b0, B}[0];
  wire _c01 = {1'b0, A}[0] & {1'b0, B}[0];
  wire _n02 = {1'b0, A}[1] ^ {1'b0, B}[1] ^ _c01;
  wire _c02 = ({1'b0, A}[1] & {1'b0, B}[1]) | ({1'b0, A}[1] & _c01) | ({1'b0, B}[1] & _c01);
  wire _n03 = {1'b0, A}[2] ^ {1'b0, B}[2] ^ _c02;
  wire _c03 = ({1'b0, A}[2] & {1'b0, B}[2]) | ({1'b0, A}[2] & _c02) | ({1'b0, B}[2] & _c02);
  wire _n04 = {1'b0, A}[3] ^ {1'b0, B}[3] ^ _c03;
  wire _c04 = ({1'b0, A}[3] & {1'b0, B}[3]) | ({1'b0, A}[3] & _c03) | ({1'b0, B}[3] & _c03);
  assign temp = {_n01, _n02, _n03, _n04};

// Assign the output signals
assign S = temp[3:0];
assign C_out = temp[4];

endmodule

