  wire _n03 = ~in[2] ^ 1[2] ^ _c02;
  wire _c03 = (~in[2] & 1[2]) | (~in[2] & _c02) | (1[2] & _c02);
  wire _n04 = ~in[3] ^ 1[3] ^ _c03;
  wire _c04 = (~in[3] & 1[3]) | (~in[3] & _c03) | (1[3] & _c03);
