module twos_complement (
    input [3:0] binary,
    output reg [3:0] twos_comp
);

  wire _n01 = (~binary)[0] ^ 1[0];
  wire _c01 = (~binary)[0] & 1[0];
  wire _n02 = (~binary)[1] ^ 1[1] ^ _c01;
  wire _c02 = ((~binary)[1] & 1[1]) | ((~binary)[1] & _c01) | (1[1] & _c01);
  wire _n03 = (~binary)[2] ^ 1[2] ^ _c02;
  wire _c03 = ((~binary)[2] & 1[2]) | ((~binary)[2] & _c02) | (1[2] & _c02);
  wire _n04 = (~binary)[3] ^ 1[3] ^ _c03;
  wire _c04 = ((~binary)[3] & 1[3]) | ((~binary)[3] & _c03) | (1[3] & _c03);
  assign twos_comp = {_n01, _n02, _n03, _n04};

endmodule

module four_bit_adder(
  input [3:0] a,
  input [3:0] b,
  input cin,
  output [3:0] sum,
  output cout
);

  wire [3:0] temp_sum;
  wire carry;

    wire _n01 = a + b[0] ^ cin[0];
  wire _c01 = a + b[0] & cin[0];
  wire _n02 = a + b[1] ^ cin[1] ^ _c01;
