  wire _c03 = (A[2] & B[2]) | (A[2] & _c02) | (B[2] & _c02);
  wire _n04 = A[3] ^ B[3] ^ _c03;
  wire _c04 = (A[3] & B[3]) | (A[3] & _c03) | (B[3] & _c03);
  assign temp_sum = {_n01, _n02, _n03, _n04};

    assign carry_out = temp_sum[8];
    assign sum = temp_sum[7:0];

endmodule

module twos_complement (
    input [3:0] binary_in,
    output reg [3:0] twos_comp_out
);

  wire _n01 = (~binary_in)[0] ^ 1[0];
  wire _c01 = (~binary_in)[0] & 1[0];
  wire _n02 = (~binary_in)[1] ^ 1[1] ^ _c01;
  wire _c02 = ((~binary_in)[1] & 1[1]) | ((~binary_in)[1] & _c01) | (1[1] & _c01);
  wire _n03 = (~binary_in)[2] ^ 1[2] ^ _c02;
  wire _c03 = ((~binary_in)[2] & 1[2]) | ((~binary_in)[2] & _c02) | (1[2] & _c02);
  wire _n04 = (~binary_in)[3] ^ 1[3] ^ _c03;
  wire _c04 = ((~binary_in)[3] & 1[3]) | ((~binary_in)[3] & _c03) | (1[3] & _c03);
  assign twos_comp_out = {_n01, _n02, _n03, _n04};

endmodule

module comparator_4bit(
    input [3:0] A,
    input [3:0] B,
    output EQ,
    output GT
    );

      wire _n01 = A[0] ^ B[0];
  wire _n02 = A[1] ^ B[1];
  wire _n03 = A[2] ^ B[2];
  wire _n04 = A[3] ^ B[3];
  assign EQ = ~_n01 & ~_n02 & ~_n03 & ~_n04;
    assign GT = (A > B);

endmodule

module binary_adder (
  input [3:0] A,
  input [3:0] B,
  input C_in,
  output [3:0] S
);

  wire [3:0] sum_wire;

    wire _n01 = A + B[0] ^ C_in[0];
  wire _c01 = A + B[0] & C_in[0];
  wire _n02 = A + B[1] ^ C_in[1] ^ _c01;
  wire _c02 = (A + B[1] & C_in[1]) | (A + B[1] & _c01) | (C_in[1] & _c01);
  wire _n03 = A + B[2] ^ C_in[2] ^ _c02;
  wire _c03 = (A + B[2] & C_in[2]) | (A + B[2] & _c02) | (C_in[2] & _c02);
  wire _n04 = A + B[3] ^ C_in[3] ^ _c03;
  wire _c04 = (A + B[3] & C_in[3]) | (A + B[3] & _c03) | (C_in[3] & _c03);
  assign sum_wire = {_n01, _n02, _n03, _n04};

  assign S = sum_wire;

endmodule

module adder_4bit(
  input [3:0] A,
  input [3:0] B,
  input CIN,
  output [3:0] S,
  output COUT
);

    wire _n01 = A + B[0] ^ CIN[0];
  wire _c01 = A + B[0] & CIN[0];
  wire _n02 = A + B[1] ^ CIN[1] ^ _c01;
  wire _c02 = (A + B[1] & CIN[1]) | (A + B[1] & _c01) | (CIN[1] & _c01);
  wire _n03 = A + B[2] ^ CIN[2] ^ _c02;
  wire _c03 = (A + B[2] & CIN[2]) | (A + B[2] & _c02) | (CIN[2] & _c02);
  wire _n04 = A + B[3] ^ CIN[3] ^ _c03;
  wire _c04 = (A + B[3] & CIN[3]) | (A + B[3] & _c03) | (CIN[3] & _c03);
  assign {COUT, S} = {_n01, _n02, _n03, _n04};

endmodule
